{
  "name": "OptiView Clinic",
  "description": "A premium dark-themed eyewear catalog featuring virtual try-on, advanced filtering, and a responsive product grid."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface Product {
    id: string;
    brand: string;
    name: string;
    price: number;
    originalPrice?: number;
    imageUrl: string;
    isNew?: boolean;
    isSale?: boolean;
    hasTryOn?: boolean;
}

export interface FilterState {
    faceShape: string[];
    gender: string[];
    priceRange: [number, number];
    materials: string[];
    colors: string[];
}

import React from 'react';
import { Product } from '../types';

interface ProductCardProps {
    product: Product;
}

const ProductCard: React.FC<ProductCardProps> = ({ product }) => {
    return (
        <div className="group relative flex flex-col rounded-xl bg-surface-dark border border-border-dark overflow-hidden hover:shadow-xl hover:border-primary/40 transition-all duration-300">
            <div className="absolute top-3 right-3 z-10 flex gap-2">
                <button className="bg-background-dark/80 backdrop-blur-sm p-1.5 rounded-full text-white cursor-pointer hover:bg-primary hover:text-white transition-colors">
                    <span className="material-symbols-outlined text-[18px]">favorite</span>
                </button>
            </div>

            {/* Badges */}
            <div className="absolute top-3 left-3 z-10 flex flex-col gap-2">
                {product.isNew && (
                    <span className="bg-primary text-white text-[10px] font-bold px-2 py-1 rounded uppercase tracking-wider shadow-sm">
                        New
                    </span>
                )}
                {product.isSale && (
                    <span className="bg-red-500 text-white text-[10px] font-bold px-2 py-1 rounded uppercase tracking-wider shadow-sm">
                        Sale
                    </span>
                )}
            </div>

            <div className="aspect-[4/3] w-full bg-white relative overflow-hidden flex items-center justify-center">
                {product.hasTryOn && (
                     <div className="absolute bottom-2 left-1/2 -translate-x-1/2 bg-background-dark/90 backdrop-blur text-white text-xs px-2 py-1 rounded-full flex items-center gap-1 opacity-90 group-hover:opacity-100 transition-opacity whitespace-nowrap z-10">
                        <span className="material-symbols-outlined text-[14px] text-primary">videocam</span>
                        Try-On Available
                     </div>
                )}
                <img 
                    src={product.imageUrl} 
                    alt={product.name}
                    className="w-full h-full object-contain object-center p-6 group-hover:scale-110 transition-transform duration-500 ease-out"
                />
            </div>

            <div className="p-4 flex flex-col gap-1 flex-1">
                <p className="text-xs font-semibold text-text-secondary uppercase tracking-wider">{product.brand}</p>
                <h3 className="text-white font-bold text-lg leading-tight truncate" title={product.name}>{product.name}</h3>

                <div className="mt-auto pt-3 flex items-center justify-between">
                    <div className="flex flex-col">
                        {product.originalPrice && (
                             <span className="text-text-secondary text-xs line-through">${product.originalPrice.toFixed(2)}</span>
                        )}
                        <span className={`${product.isSale ? 'text-red-400' : 'text-primary'} font-bold text-lg`}>
                            ${product.price.toFixed(2)}
                        </span>
                    </div>

                    <button className="bg-border-dark hover:bg-primary text-white p-2 rounded-lg transition-colors flex items-center justify-center">
                        <span className="material-symbols-outlined text-[20px]">add_shopping_cart</span>
                    </button>
                </div>
            </div>
        </div>
    );
};

export default ProductCard;

import React, { useState } from 'react';

const Sidebar: React.FC = () => {
    const [priceMin, setPriceMin] = useState(50);
    const [priceMax, setPriceMax] = useState(450);

    return (
        <aside className="w-full lg:w-64 shrink-0 space-y-6">
             {/* Mobile Filter Toggle (Visible only on small screens) */}
            <button className="lg:hidden w-full flex items-center justify-between bg-surface-dark p-4 rounded-lg border border-border-dark text-white font-medium hover:bg-border-dark transition-colors">
                <span>Show Filters</span>
                <span className="material-symbols-outlined">filter_list</span>
            </button>

            <div className="hidden lg:flex flex-col gap-6">
                {/* Header */}
                <div className="flex items-center justify-between">
                    <span className="text-white font-semibold">Filters</span>
                    <button className="text-xs text-primary hover:text-white transition-colors">Clear All</button>
                </div>

                {/* Face Shape */}
                <div className="space-y-3 border-t border-border-dark pt-4">
                    <h3 className="text-sm font-medium text-white flex justify-between cursor-pointer group">
                        Face Shape
                        <span className="material-symbols-outlined text-text-secondary text-sm group-hover:text-white">remove</span>
                    </h3>
                    <div className="grid grid-cols-2 gap-2">
                        {[
                            { name: 'Oval', style: 'rounded-full' },
                            { name: 'Round', style: 'rounded-full' },
                            { name: 'Square', style: 'rounded-sm' },
                            { name: 'Heart', clipPath: 'polygon(50% 0%, 100% 35%, 80% 100%, 20% 100%, 0% 35%)' }
                        ].map((shape) => (
                            <label key={shape.name} className="cursor-pointer flex flex-col items-center gap-2 p-2 rounded border border-border-dark bg-surface-dark hover:border-primary/50 transition-all">
                                <input type="checkbox" className="hidden peer" />
                                <div 
                                    className={`w-8 h-8 border border-dashed border-text-secondary peer-checked:border-primary peer-checked:bg-primary/10 ${shape.style || ''}`}
                                    style={shape.clipPath ? { clipPath: shape.clipPath, backgroundColor: 'transparent' } : undefined}
                                ></div>
                                <span className="text-xs text-text-secondary peer-checked:text-white">{shape.name}</span>
                            </label>
                        ))}
                    </div>
                </div>

                {/* Gender */}
                <div className="space-y-3 border-t border-border-dark pt-4">
                    <h3 className="text-sm font-medium text-white">Gender</h3>
                    <div className="space-y-2">
                        {['Men', 'Women', 'Unisex', 'Kids'].map((gender) => (
                            <label key={gender} className="flex items-center gap-3 cursor-pointer group">
                                <input type="checkbox" className="form-checkbox rounded border-border-dark bg-surface-dark text-primary focus:ring-0 focus:ring-offset-0" />
                                <span className="text-sm text-text-secondary group-hover:text-white transition-colors">{gender}</span>
                            </label>
                        ))}
                    </div>
                </div>

                {/* Price Range */}
                <div className="space-y-3 border-t border-border-dark pt-4">
                    <h3 className="text-sm font-medium text-white">Price Range</h3>
                    <div className="flex items-center gap-2">
                        <div className="relative flex-1">
                            <span className="absolute left-3 top-2 text-text-secondary text-xs">$</span>
                            <input 
                                type="number" 
                                value={priceMin}
                                onChange={(e) => setPriceMin(Number(e.target.value))}
                                className="w-full bg-surface-dark border border-border-dark rounded px-2 py-1 pl-6 text-sm text-white focus:border-primary focus:outline-none focus:ring-1 focus:ring-primary"
                            />
                        </div>
                        <span className="text-text-secondary text-sm">-</span>
                         <div className="relative flex-1">
                            <span className="absolute left-3 top-2 text-text-secondary text-xs">$</span>
                            <input 
                                type="number" 
                                value={priceMax}
                                onChange={(e) => setPriceMax(Number(e.target.value))}
                                className="w-full bg-surface-dark border border-border-dark rounded px-2 py-1 pl-6 text-sm text-white focus:border-primary focus:outline-none focus:ring-1 focus:ring-primary"
                            />
                        </div>
                    </div>
                    <input 
                        type="range" 
                        min="0" 
                        max="1000" 
                        value={priceMax} 
                        onChange={(e) => setPriceMax(Number(e.target.value))}
                        className="w-full h-1 bg-border-dark rounded-lg appearance-none cursor-pointer accent-primary" 
                    />
                </div>

                {/* Material */}
                <div className="space-y-3 border-t border-border-dark pt-4">
                    <h3 className="text-sm font-medium text-white">Material</h3>
                    <div className="space-y-2">
                        {['Acetate', 'Titanium', 'Metal Alloy'].map((material, idx) => (
                            <label key={material} className="flex items-center gap-3 cursor-pointer group">
                                <input 
                                    type="checkbox" 
                                    defaultChecked={idx === 1} // Check Titanium as per screenshot
                                    className="form-checkbox rounded border-border-dark bg-surface-dark text-primary focus:ring-0 focus:ring-offset-0" 
                                />
                                <span className="text-sm text-text-secondary group-hover:text-white transition-colors">{material}</span>
                            </label>
                        ))}
                    </div>
                </div>

                 {/* Colors */}
                 <div className="space-y-3 border-t border-border-dark pt-4">
                    <h3 className="text-sm font-medium text-white">Color</h3>
                    <div className="flex flex-wrap gap-2">
                        {[
                            '#000000', // Black
                            '#8B4513', // Brown
                            '#D4AF37', // Gold
                            '#94a3b8', // Silver/Grey
                            '#7f1d1d', // Red
                            '#1e3a8a', // Blue
                        ].map((color) => (
                            <button 
                                key={color}
                                className="w-6 h-6 rounded-full border border-white/10 hover:scale-110 focus:ring-2 focus:ring-primary ring-offset-2 ring-offset-surface-dark transition-all"
                                style={{ backgroundColor: color }}
                                aria-label={`Select color ${color}`}
                            />
                        ))}
                    </div>
                </div>
            </div>
        </aside>
    );
};

export default Sidebar;

import React from 'react';

const Pagination: React.FC = () => {
    return (
        <div className="flex items-center justify-center gap-2 mt-12 mb-4">
            <button className="size-10 flex items-center justify-center rounded-lg bg-surface-dark text-white border border-border-dark hover:bg-border-dark transition-colors disabled:opacity-50">
                <span className="material-symbols-outlined">chevron_left</span>
            </button>
            <button className="size-10 flex items-center justify-center rounded-lg bg-primary text-white font-bold transition-colors">1</button>
            <button className="size-10 flex items-center justify-center rounded-lg bg-surface-dark text-text-secondary border border-border-dark hover:text-white hover:bg-border-dark transition-colors">2</button>
            <button className="size-10 flex items-center justify-center rounded-lg bg-surface-dark text-text-secondary border border-border-dark hover:text-white hover:bg-border-dark transition-colors">3</button>
            <span className="text-text-secondary px-2">...</span>
            <button className="size-10 flex items-center justify-center rounded-lg bg-surface-dark text-text-secondary border border-border-dark hover:text-white hover:bg-border-dark transition-colors">12</button>
            <button className="size-10 flex items-center justify-center rounded-lg bg-surface-dark text-white border border-border-dark hover:bg-border-dark transition-colors">
                <span className="material-symbols-outlined">chevron_right</span>
            </button>
        </div>
    );
};

export default Pagination;

