  "name": "OptiView Clinic",
  "description": "A premium dark-themed eyewear catalog featuring virtual try-on, advanced filtering, and a responsive product grid.",
  "requestFramePermissions": [
    "camera"
  ]
}

import React from 'react';
import Header from './components/Header';
import VirtualTryOn from './components/VirtualTryOn';

const App: React.FC = () => {
  return (
    <div className="h-screen flex flex-col bg-background-light dark:bg-background-dark text-slate-900 dark:text-white font-display overflow-hidden">
      <Header />
      <VirtualTryOn />
    </div>
  );
};

export default App;
